import React, { Fragment, useContext,useRef } from 'react'
import {InputContext} from './SearchBarContent';
import { Html5Qrcode } from "html5-qrcode";
import {setSearchTerm} from '../store/linksSlice'
import { useDispatch, useSelector } from 'react-redux';

  
export default function ButtonComponents() {
const {textValue,SettextValue,voiceState,Setvoicestate}=useContext(InputContext);
const fileInputRef = useRef(null);
  const html5QrCodeRef = useRef(null);
  const dispatch=useDispatch();
  const results = useSelector((state) => state.linksData.results)

const handleQR = async () => {
  if (!html5QrCodeRef.current) {
    html5QrCodeRef.current = new Html5Qrcode("reader");
  }

  try {
    await html5QrCodeRef.current.stop();
  } catch {}

  const config = { fps: 10, qrbox: { width: 250, height: 250 } };

    console.log("Desktop detected → open file upload");
    fileInputRef.current.click();
    return;


};



const handleFileChange = async (e) => {
  if (e.target.files.length === 0) return;
  const imageFile = e.target.files[0];

  if (!html5QrCodeRef.current) {
    html5QrCodeRef.current = new Html5Qrcode("reader");
  }

  try {
    await html5QrCodeRef.current.stop().catch(() => {});
  } catch {}

  html5QrCodeRef.current
    .scanFile(imageFile, false)
    .then(decodedText => {
      SettextValue(decodedText);
      dispatch(setSearchTerm(decodedText));
  html5QrCodeRef.current.clear(); 
    })
    .catch(err => {
      alert("QR code not found in this photo!");
      console.error(err);
    });
};

const handleVoice=()=>{
  const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

if (SpeechRecognition) {
    const recognition = new SpeechRecognition();
    recognition.lang = 'en'; 

        recognition.start();

        Setvoicestate(true);
        recognition.onend=()=>{

          Setvoicestate(false);
        }

    recognition.onresult = (event) => {
        const transcript = event.results[0][0].transcript;
        if(transcript){SettextValue(transcript);
          dispatch(setSearchTerm(transcript));
        }
        Setvoicestate(false);
    };
    recognition.onerror = (event) => {
      console.error("error in mic", event.error);
        Setvoicestate(true);
    };
}else{
  alert('your browser not support voice recognition')
}
}

const handleSubmit=()=>{
  if(results.length>0){
    window.open(results[0].url, '_blank', 'noopener,noreferrer');
  }
}

const QRbtn=()=>{
  return(        
    <Fragment>
      <button id="qr-btn" onClick={handleQR}><i className="fa-solid fa-qrcode"></i></button>
      <input type='file' onChange={handleFileChange} ref={fileInputRef} accept="image/*" style={{display:'none'}}/>
    </Fragment>    
  )
}
const Voicebtn=()=>{
  return(            
  <button id="voice-btn" onClick={handleVoice} style={{ color: voiceState ? 'red' : '' }}><i className="fa-solid fa-microphone"></i></button>
)
}
const Submitbtn=()=>{
  return(         
  <button id="submit-btn" onClick={handleSubmit}><i className="fa-brands fa-searchengin"></i></button>
)
}
ButtonComponents.QR=QRbtn;
ButtonComponents.Voice=Voicebtn;
ButtonComponents.Submit=Submitbtn;
  

  return (
<div className='buttons-container'>  
    <div id="reader"></div>  
    <ButtonComponents.QR />
    <ButtonComponents.Voice />
    <ButtonComponents.Submit /></div>
  )
}
      
