import { createSlice } from "@reduxjs/toolkit";
import DataLinks from "./data/static_index.json";

const initialState = {
    links: DataLinks,
    searchTerm: "",
    results: [],
};

const linksSlice = createSlice({
    name: "Links",
    initialState,
    reducers: {
    setSearchTerm: (state, action) => {
        state.searchTerm = action.payload;

        const term = action.payload.toLowerCase().trim();

        if (!term) {
        state.results = [];
        return;
        }

        const words = term.split(/\s+/).filter(Boolean);

        const temp = {};        
        const matchCount = {};  
        const wordSets = {};    

        for (let key in state.links) {
        const keyLower = key.toLowerCase();

        for (let word of words) {
            if (!keyLower.includes(word)) continue;

            const urls = state.links[key].urls;

            for (let url in urls) {
            if (!temp[url]) {
                temp[url] = 0;
                matchCount[url] = 0;
                wordSets[url] = new Set();
            }

            temp[url] += urls[url];

            if (!wordSets[url].has(word)) {
                wordSets[url].add(word);
                matchCount[url] += 1;
            }
            }
        }
        }

        let results = Object.entries(temp).filter(
        ([url]) => matchCount[url] === words.length
        );

        if (results.length === 0) {
        results = Object.entries(temp);
        }


        state.results = results
        .map(([url, count]) => ({ url, count }))
        .sort((a, b) => {
            const wordDiff = matchCount[b.url] - matchCount[a.url];
            if (wordDiff !== 0) return wordDiff;

            return b.count - a.count;
        })
        .slice(0, 10);
    },
    },
});

export const { setSearchTerm } = linksSlice.actions;
export default linksSlice.reducer;