import React, { createContext, useEffect, useRef, useState } from 'react'
import ButtonComponents from './ButtonComponents'
import SearchLinks from './SearchLinks';
import { useDispatch, useSelector } from 'react-redux';
import { setSearchTerm } from '../store/linksSlice'


export  const InputContext= createContext();
export default function SearchBarContent() {
  const dispatch=useDispatch();
  const [textValue,SettextValue]=useState('');
  const [voiceState,Setvoicestate]=useState(false);
  const inputReference=useRef();
  const timerRef = useRef();
  const results = useSelector((state) => state.linksData.results)


useEffect(()=>{
inputReference.current.focus();
},[textValue])

const handleSubmit=()=>{
  if(results.length>0){
    window.open(results[0].url, '_blank', 'noopener,noreferrer');
  }
}
const handleKeyDown = (e) => {
  if (e.key === 'Enter') {
    handleSubmit(); 
  }
};

const handleChange=(e)=>{
SettextValue(e.target.value);

if (timerRef.current) {
      clearTimeout(timerRef.current);
    }

    timerRef.current = setTimeout(() => {
      dispatch(setSearchTerm(e.target.value));
    }, 500);
}
  return (
    <InputContext.Provider value={{textValue,SettextValue,voiceState,Setvoicestate}} >
    <div className="search-wrapper">
        <input ref={inputReference} onKeyDown={handleKeyDown} onChange={handleChange} value={textValue} type="text" id="search-input" placeholder="Search Here..." />
        <ButtonComponents />
        <SearchLinks />
        </div>
        </InputContext.Provider>
  )
}
