import React from 'react'
import { useSelector } from 'react-redux'

export default function SearchLinks() {
    const results = useSelector((state) => state.linksData.results)
    const searchTerm = useSelector((state) => state.linksData.searchTerm)

    if (!searchTerm) return null;

    return (
    <div className='results-container'>
        {results.length === 0 ? (
        <p className="no-results">No results found</p>
        ) : (
        results.map((item, index) => (
            <div className="result-card" key={index}>
            <a href={item.url} target="_blank" className="result-link">
                {item.url}
            </a>
            <p className="result-count">Shown {item.count} times</p>
            </div>
        ))
        )}
    </div>
    )
}